#!/usr/bin/env node

/**
 * Called by npm `version` lifecycle hook.
 * Propagates the new root version to all workspace modules and updates currentVersion.ts.
 */

import { readFileSync, writeFileSync } from 'fs';

const rootPkg = JSON.parse(readFileSync('./package.json', 'utf-8'));
const version = rootPkg.version;

// Update currentVersion.ts (source) — build output is generated by tsc
const currentVersionFile = './modules/core/src/currentVersion.ts';
writeFileSync(currentVersionFile, `export const currentVersion = '${version}';\n`);
console.info(`updated ${currentVersionFile} to ${version}`);

// Read workspace module list from tsconfig references
const tsconfig = JSON.parse(readFileSync('./modules/tsconfig.json', 'utf-8'));
const modulePaths = tsconfig.references.map((ref) => `./modules/${ref.path}`);

for (const modulePath of modulePaths) {
	const pkgFile = `${modulePath}/package.json`;
	const pkg = JSON.parse(readFileSync(pkgFile, 'utf-8'));
	pkg.version = version;
	writeFileSync(pkgFile, JSON.stringify(pkg, null, 2) + '\n');
	console.info(`updated ${pkg.name} to ${version}`);
}

// Stage all changed files so npm version's auto-commit includes them
const { execSync } = await import('child_process');
execSync(`git add ${currentVersionFile} ${modulePaths.map((m) => `${m}/package.json`).join(' ')}`, { stdio: 'inherit' });
